import json
from pydantic import BaseModel, ValidationError
from anthropic import Anthropic

client = Anthropic()

class TicketClassification(BaseModel):
    category: str
    urgency: str  # "high" | "low" | "none"
    sentiment: str  # "positive" | "neutral" | "negative"

def classify_ticket(text: str, max_retries: int = 2) -> TicketClassification:
    for attempt in range(max_retries + 1):
        resp = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=128,
            system=FEW_SHOT_SYSTEM,
            messages=[{"role": "user", "content": text}]
        )
        raw = resp.content[0].text.strip()
        try:
            data = json.loads(raw)
            return TicketClassification(**data)
        except (json.JSONDecodeError, ValidationError) as e:
            if attempt == max_retries:
                raise ValueError(f"Model returned invalid format after {max_retries+1} attempts: {raw}") from e
            # Re-prompt with the error context
            text = f"{text}\n\nYour previous response was invalid JSON: {raw}. Respond with valid JSON only."
    raise RuntimeError("unreachable")

def format_compliance_rate(
    prompt: str,
    validator,  # fn(str) -> bool
    n_runs: int = 10,
    model: str = "claude-opus-4-8"
) -> float:
    """Fraction of N runs that produce format-valid output."""
    passes = 0
    for _ in range(n_runs):
        resp = client.messages.create(
            model=model, max_tokens=512,
            messages=[{"role": "user", "content": prompt}]
        )
        if validator(resp.content[0].text):
            passes += 1
    return passes / n_runs

def structure_fingerprint(text: str) -> str:
    """Reduce text to a structural signature for comparison."""
    lines = text.strip().splitlines()
    sig = []
    for line in lines:
        if line.startswith('{') or line.startswith('['):
            sig.append('JSON')
        elif re.match(r'^\s*[-•]', line):
            sig.append('BULLET')
        elif re.match(r'^\s*\d+\.', line):
            sig.append('NUMBERED')
        elif re.match(r'^#+\s', line):
            sig.append('HEADER')
        elif line.strip():
            sig.append('PARA')
    return '|'.join(sig)

def inter_run_consistency(outputs: list[str]) -> float:
    """Fraction of (i,j) pairs with identical structural fingerprint."""
    fps = [structure_fingerprint(o) for o in outputs]
    pairs = [(fps[i], fps[j]) for i in range(len(fps)) for j in range(i+1, len(fps))]
    return sum(a == b for a, b in pairs) / len(pairs) if pairs else 1.0

import json
from pydantic import BaseModel, ValidationError
from typing import Callable

class FormatTest:
    def __init__(
        self,
        name: str,
        prompt: str,
        validator: Callable[[str], bool],
        n_runs: int = 5
    ):
        self.name = name
        self.prompt = prompt
        self.validator = validator
        self.n_runs = n_runs

    def run(self, answer_fn: Callable[[str], str]) -> dict:
        results = [self.validator(answer_fn(self.prompt)) for _ in range(self.n_runs)]
        pass_rate = sum(results) / self.n_runs
        return {
            "test": self.name,
            "pass_rate": pass_rate,
            "passed": pass_rate == 1.0,
            "runs": self.n_runs
        }

# Define format tests for a ticket classifier
def is_valid_ticket_json(text: str) -> bool:
    try:
        data = json.loads(text)
        required = {"category", "urgency", "sentiment"}
        return required.issubset(data.keys())
    except json.JSONDecodeError:
        return False

FORMAT_TESTS = [
    FormatTest("short input", "My order is late.", is_valid_ticket_json),
    FormatTest("long input", "I've been a customer for 5 years and this is the worst experience I've ever had. The product broke after 2 days and customer service hasn't responded in a week. I want a full refund immediately.", is_valid_ticket_json),
    FormatTest("non-english", "Mi pedido no ha llegado.", is_valid_ticket_json),
    FormatTest("empty-ish", "?", is_valid_ticket_json),
]

def run_format_regression(answer_fn: Callable[[str], str]) -> list[dict]:
    return [t.run(answer_fn) for t in FORMAT_TESTS]
